// Final Code node ("Code — Inject") for the Interconnect Publisher workflow.
// Pulls STRUCTURED JSON from upstream nodes and injects it into the LOCKED design
// template via string replacement. NO HTML is generated by AI — the shell is fixed.
//
// UPSTREAM FIELD CONTRACT (what each node must provide):
//   Set Metadata        -> json: { dateline, vol, no }
//   Generate Lede       -> Claude API response; parsed JSON: { lede: string }
//   Generate Signals    -> Claude API response; parsed JSON: array of
//                          { iso, location, category, headline, detail, angle, variant }
//                          variant: '' (standard) | 'flag' (risk) | 'gold' (opportunity)
//                          iso: PJM | WECC | MISO | ERCOT | CAISO | NYISO | SPP
//   Generate Connectors -> Claude API response; parsed JSON: array of
//                          { demand_market, demand_text, supply_market, supply_text }
//   Fetch Queue Records -> Airtable rows, mapped here:
//                          project <- 'Project Name', iso <- 'Region', type <- 'Generation Type',
//                          mw <- 'MW Capacity', status <- 'Status', poi <- 'POI Name'
