  font-style: normal;
  color: var(--accent);
}
.masthead h1 sup {
  font-size: 22px;
  vertical-align: super;
  letter-spacing: 0;
  color: var(--accent);
}
.tagline {
  font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
  font-size: 13px;
  color: var(--muted);
  line-height: 1.45;
  max-width: 560px;
  margin-bottom: 18px;
}

/* ── DATELINE BAR ── */
.dateline-bar {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
  padding: 10px 44px;
  border-top: 1px solid var(--ink);
  border-bottom: 2px solid var(--ink);
  background: var(--paper);
  font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
