  font-size: 8.5px;
  font-weight: 700;
  letter-spacing: 3.5px;
  text-transform: uppercase;
  color: var(--accent);
  margin-bottom: 14px;
  padding-bottom: 5px;
  border-bottom: 1px solid var(--accent);
  display: inline-block;
