}
</style>
</head>
<body>
<div class="sheet">

  <!-- MASTHEAD -->
  <div class="masthead">
    <div class="kicker">NexPhase Advisory &nbsp;·&nbsp; Power Market Intelligence</div>
    <h1>The <em>Inter</em>connect<sup>&#8482;</sup></h1>
    <p class="tagline">Weekly intelligence on power procurement, interconnection queues, and data center development — for teams building at the grid edge.</p>
  </div>

  <!-- DATELINE BAR -->
  <div class="dateline-bar">
    <div class="vol">{{DATELINE}} <span>· Vol. {{VOL}}, No. {{NO}}</span></div>
    <div class="site">NexPhaseAdvisory.net</div>
  </div>

  <!-- BODY -->
  <div class="body-wrap">

    <!-- LEDE -->
    <p class="lede">{{LEDE}}</p>

    <!-- SIGNALS SECTION -->
    <div class="section-label">This Week's Signals</div>
    {{SIGNAL_CARDS}}

    <hr class="section-divider">

    <!-- CONNECTOR MARKETS -->
    <div class="section-label">Connector Markets</div>
    <div class="connector-grid">
      {{CONNECTOR_MARKETS}}
    </div>

    <hr class="section-divider">

    <!-- QUEUE SPOTLIGHT -->
    <div class="section-label">Queue Spotlight</div>
    <table class="queue-table">
      <thead>
        <tr>
          <th>Project</th>
          <th>ISO</th>
          <th>Type</th>
          <th>MW</th>
          <th>Status</th>
          <th>POI / Substation</th>
        </tr>
      </thead>
      <tbody>
        {{QUEUE_ROWS}}
      </tbody>
    </table>

  </div><!-- /body-wrap -->

  <!-- FOOTER -->
  <div class="footer">
    <strong>NexPhase Advisory</strong> &nbsp;·&nbsp; Power Market Intelligence<br>
    Questions or comments: <a href="mailto:info@nexphaseadvisory.net">info@nexphaseadvisory.net</a><br><br>
    This publication is provided for informational purposes only. Nothing herein constitutes legal, financial, or investment advice.
    All queue data derived from public ISO sources. &copy; {{YEAR}} NexPhase Advisory. All rights reserved.<br><br>
    To unsubscribe, reply with "unsubscribe" in the subject line.
  </div>

</div><!-- /sheet -->
</body>
</html>`;

// ---------- helpers ----------
function claudeJSON(resp) {
  // resp is the raw Anthropic /v1/messages response object from a Generate node.
  try {
    const content = (resp && resp.content) || [];
    const text = content.filter(b => b && b.type === 'text').map(b => b.text).join('').trim();
    const cleaned = text.replace(/```json|```/g, '').trim();
    return JSON.parse(cleaned);
  } catch (e) {
    return null;
  }
}
function esc(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
const ISO_BADGE = { PJM: 'badge-pjm', WECC: 'badge-wecc', MISO: 'badge-miso', ERCOT: 'badge-ercot', CAISO: 'badge-caiso', FRCC: 'badge-frcc', SERC: 'badge-serc', NYISO: 'badge-pjm', SPP: 'badge-pjm' };
function badgeClass(iso) { return ISO_BADGE[String(iso || '').toUpperCase()] || 'badge-pjm'; }
// Queue "ISO" derived from the Utility field (queue table has no true ISO field).
function isoFromUtility(u) {
  const s = String(u || '');
  // Florida utilities -> FRCC (check before the generic Duke -> SERC rule)
  if (/Florida Power|Duke Energy Florida|Tampa Electric|Gulf Power/i.test(s)) return 'FRCC';
  // Duke Carolinas / other Duke -> SERC
  if (/Duke/i.test(s)) return 'SERC';
  // RTOs
  if (/PJM/i.test(s)) return 'PJM';
  if (/CAISO/i.test(s)) return 'CAISO';
  if (/MISO/i.test(s)) return 'MISO';
  return s; // default: utility value as-is
}

// ---------- pull upstream ----------
const meta = $('Set Metadata').first().json;
const ledeObj = claudeJSON($('Generate Lede').first().json) || { lede: '' };
const signals = claudeJSON($('Generate Signals').first().json) || [];
const connectors = claudeJSON($('Generate Connectors').first().json) || [];
const queueRaw = $('Fetch Queue Records').all().map(i => i.json);

// ---------- build SIGNAL_CARDS ----------
const signalCards = (Array.isArray(signals) ? signals : []).map(s => {
  const variant = (s.variant === 'flag' || s.variant === 'gold') ? ' ' + s.variant : '';
  return '<div class="signal-card' + variant + '">\n' +
    '      <div class="signal-meta">\n' +
    '        <span class="badge ' + badgeClass(s.iso) + '">' + esc(s.iso) + '</span>\n' +
    '        ' + esc(s.location) + ' · ' + esc(s.category) + '\n' +
    '      </div>\n' +
    '      <h3>' + esc(s.headline) + '</h3>\n' +
    '      <p>' + esc(s.detail) + '</p>\n' +
    '      <div class="angle">\n' +
    '        <strong>The Angle</strong>\n' +
    '        ' + esc(s.angle) + '\n' +
    '      </div>\n' +
    '    </div>';
}).join('\n');

// ---------- build CONNECTOR_MARKETS (each pairing = demand cell + supply cell) ----------
const connectorCells = (Array.isArray(connectors) ? connectors : []).map(c => {
  return '<div class="connector-cell demand">\n' +
    '        <div class="cell-label">Demand Signal</div>\n' +
    '        <h4>' + esc(c.demand_market) + '</h4>\n' +
    '        <p>' + esc(c.demand_text) + '</p>\n' +
    '      </div>\n' +
    '      <div class="connector-cell">\n' +
    '        <div class="cell-label">Supply Context</div>\n' +
    '        <h4>' + esc(c.supply_market) + '</h4>\n' +
    '        <p>' + esc(c.supply_text) + '</p>\n' +
    '      </div>';
}).join('\n');

// ---------- build QUEUE_ROWS (map Airtable fields; cap for spotlight) ----------
const QUEUE_CAP = 8;
const queueRows = queueRaw.map(q => ({
  project: q['Project Name'] || q['POI Name'] || '',
  iso: isoFromUtility(q['Utility']),
  type: q['Generation Type'] || q['Project Type'] || '',
  mw: (q['MW Capacity'] != null ? q['MW Capacity'] : ''),
  status: q['Status'] || '',
  poi: q['POI Name'] || ''
}))
  .sort((a, b) => (parseFloat(b.mw) || 0) - (parseFloat(a.mw) || 0))
  .slice(0, QUEUE_CAP)
  .map(q =>
    '<tr>\n' +
    '          <td>' + esc(q.project) + '</td>\n' +
    '          <td>' + esc(q.iso) + '</td>\n' +
    '          <td>' + esc(q.type) + '</td>\n' +
    '          <td class="mw">' + esc(q.mw) + '</td>\n' +
    '          <td>' + esc(q.status) + '</td>\n' +
    '          <td>' + esc(q.poi) + '</td>\n' +
    '        </tr>'
  ).join('\n');

// ---------- inject ----------
const year = new Date().getFullYear();
const html = TEMPLATE
  .split('{{DATELINE}}').join(esc(meta.dateline))
  .split('{{VOL}}').join(esc(meta.vol))
  .split('{{NO}}').join(esc(meta.no))
  .split('{{LEDE}}').join(esc(ledeObj.lede))
  .split('{{SIGNAL_CARDS}}').join(signalCards)
  .split('{{CONNECTOR_MARKETS}}').join(connectorCells)
  .split('{{QUEUE_ROWS}}').join(queueRows)
  .split('{{YEAR}}').join(String(year));

const filename = 'interconnect-vol' + meta.vol + '-no' + meta.no + '.html';

return [{ json: { html, filename, vol: meta.vol, no: meta.no, dateline: meta.dateline } }];

// Persist the generated draft in workflow static data, keyed by vol/no.
const sd = $getWorkflowStaticData('global');
const j = $input.first().json;
const rec = { html: j.html, filename: j.filename, vol: j.vol, no: j.no, dateline: j.dateline };
sd['draft_' + j.vol + '_' + j.no] = rec;  // keyed by vol/no
sd.latestDraft = rec;                      // pointer to most recent draft
return [{ json: j }];  // pass through for the draft email

// Publish path: read the stored draft from static data and hand it to GitHub — Publish.
const sd = $getWorkflowStaticData('global');
const j = ($input.first() && $input.first().json) || {};
const body = j.body || {};  // optional { vol, no } in the publish webhook POST body
let rec = (body.vol != null && body.no != null) ? sd['draft_' + body.vol + '_' + body.no] : sd.latestDraft;
if (!rec || !rec.html) { throw new Error('No stored draft found to publish. Fire the draft webhook first.'); }
return [{ json: rec }];

const now = new Date();
const dateline = 'Week of ' + now.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric', timeZone: 'America/New_York' });
// Vol/No hardcoded for now; auto-increment later.
return [{ json: { dateline, vol: 1, no: 2 } }];

